const FORMATION_4_3_3 = { GK: 1, CB: 2, LB: 1, RB: 1, CM: 2, CDM: 1, LW: 1, RW: 1, ST: 1 };
const FORMATION_4_4_2 = { GK: 1, CB: 2, LB: 1, RB: 1, CM: 3, CAM: 0, CDM: 1, LW: 0, RW: 0, ST: 2 };
const FORMATION_3_5_2 = { GK: 1, CB: 3, LB: 1, RB: 1, CM: 3, CDM: 1, LW: 0, RW: 0, ST: 2 };

function getPlayer(id) { return PLAYERS.find(p => p.id === id); }

function searchPlayer(query) {
  const q = query.toLowerCase();
  return PLAYERS.filter(p => p.name.toLowerCase().includes(q) || p.club.toLowerCase().includes(q) || p.pos.toLowerCase() === q);
}

function calcTeamRating(team) {
  if (!team || team.length === 0) return 0;
  return Math.round(team.reduce((s, p) => s + p.rating, 0) / team.length);
}

function simulateMatch(team1, team2) {
  const r1 = calcTeamRating(team1);
  const r2 = calcTeamRating(team2);
  const diff = r1 - r2;
  const base1 = 50 + diff * 3 + Math.random() * 20;
  const base2 = 50 - diff * 3 + Math.random() * 20;
  const score1 = Math.max(0, Math.round(base1 / 25));
  const score2 = Math.max(0, Math.round(base2 / 25));
  return { score1, score2, winner: score1 > score2 ? 1 : score2 > score1 ? 2 : 0 };
}

module.exports = { PLAYERS, POSITIONS, FORMATION_4_3_3, FORMATION_4_4_2, FORMATION_3_5_2, getPlayer, searchPlayer, calcTeamRating, simulateMatch };
